/**
 * Generate ZPL code for a stock pallet label (4x6")
 *
 * Used when printing labels for pallet-stored stock in the Stock Explorer
 * and Receiving reprint flow. Displays product info, barcode, owner, and
 * quantity on a large 4x6" label suitable for sticking on wrapped pallets.
 *
 * @example
 *   generateStockPalletLabelZpl({
 *     productName: 'Chateau Margaux 2015',
 *     producer: 'Chateau Margaux',
 *     lwin18: '1010279-2015-06-00750',
 *     packSize: '6x75cl',
 *     vintage: 2015,
 *     ownerName: 'Cru Wine',
 *     quantityCases: 52,
 *     lotNumber: '2026-01-31-001',
 *   });
 */

export interface StockPalletLabelData {
  /** Product name (e.g., Chateau Margaux 2015) */
  productName: string;
  /** Producer/winery name */
  producer?: string;
  /** LWIN-18 code */
  lwin18: string;
  /** Pack size (e.g., 6x75cl) */
  packSize: string;
  /** Vintage year */
  vintage?: number | string;
  /** Stock owner name */
  ownerName: string;
  /** Number of cases on the pallet */
  quantityCases: number;
  /** Lot number */
  lotNumber?: string;
}

/**
 * Normalize accented characters to ASCII equivalents for thermal printers
 */
const normalizeAccents = (str: string) => {
  return str
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/œ/g, 'oe')
    .replace(/Œ/g, 'OE')
    .replace(/æ/g, 'ae')
    .replace(/Æ/g, 'AE')
    .replace(/ß/g, 'ss');
};

/**
 * Escape special characters for ZPL
 */
const escapeZpl = (str: string) => {
  return normalizeAccents(str).replace(/\^/g, ' ').replace(/~/g, ' ');
};

/**
 * Truncate string to max length with ellipsis
 */
const truncate = (str: string, maxLen: number) => {
  if (str.length <= maxLen) return str;
  return str.slice(0, maxLen - 3) + '...';
};

/**
 * Split text into two lines at a word boundary
 */
const splitToTwoLines = (str: string, maxCharsPerLine: number): [string, string] => {
  if (str.length <= maxCharsPerLine) {
    return [str, ''];
  }
  let breakPoint = str.lastIndexOf(' ', maxCharsPerLine);
  if (breakPoint === -1 || breakPoint < maxCharsPerLine / 2) {
    breakPoint = maxCharsPerLine;
  }
  const line1 = str.slice(0, breakPoint).trim();
  const line2 = str.slice(breakPoint).trim();
  if (line2.length > maxCharsPerLine) {
    return [line1, line2.slice(0, maxCharsPerLine - 3) + '...'];
  }
  return [line1, line2];
};

/** C&C logo as ZPL graphic (400x119 dots, reused from dispatch label) */
const LOGO_GF =
  '^GFA,5950,5950,50,';

/** Instagram icon (24x24 bitmap) */
const INSTAGRAM_ICON =
  '^GFA,72,72,3,0000000FFFF01FFFF83C003C70000E7000EE607EE660FFE661E7866381C66381C66300C66300C66381C66381C661E78660FF06607E0670000E70000E3C003C1FFFF80FFFF0000000';

/** Globe icon (24x24 bitmap) */
const GLOBE_ICON =
  '^GFA,72,72,3,00000000FF0003FFC007FFE00F7EF01CE73838E71C38C31C71C38E71C38E71C38E7FFFFE7FFFFE71C38E71C38E71C38E38C31C38E71C1CE7380F7EF007FFE003FFC000FF00000000';

/**
 * Generate ZPL code for a stock pallet label
 *
 * Label layout (4" x 6" at 203 DPI = 812 x 1218 dots):
 * - Border around entire label
 * - Top: C&C logo (left) + PALLET badge (right)
 * - Barcode (Code 128, PLT-{lwin18})
 * - Product name (large, up to 2 lines)
 * - Producer
 * - Vintage + Pack size
 * - Owner (left) + Cases count (right, large)
 * - Lot number + LWIN
 * - QR code + social footer
 */
const generateStockPalletLabelZpl = (data: StockPalletLabelData) => {
  const [productLine1, productLine2] = splitToTwoLines(
    escapeZpl(truncate(data.productName, 60)),
    22,
  );
  const producer = data.producer ? escapeZpl(truncate(data.producer, 40)) : '';
  const lwin = escapeZpl(data.lwin18.replace(/^SKU-/, ''));
  const packSize = escapeZpl(data.packSize || '-');
  const vintage = data.vintage ? String(data.vintage) : '';
  const ownerName = escapeZpl(truncate(data.ownerName, 30));
  const lotNumber = data.lotNumber ? escapeZpl(truncate(data.lotNumber, 40)) : '';
  const barcodeValue = `PLT-${data.lwin18.replace(/^SKU-/, '')}`;

  // Build ZPL lines with a running Y cursor for clean dynamic layout
  const lines: string[] = [];
  let y = 0;

  // Border around label (inset 10 dots from edge for printable area)
  lines.push('^FO10,10\n^GB792,1198,3^FS');

  // Header: logo + PALLET badge (white on black)
  lines.push(`^FO30,25\n${LOGO_GF}^FS`);
  lines.push('^FO555,22\n^GB235,75,75^FS');
  lines.push('^FO580,33\n^A0N,55,55\n^FR\n^FDPALLET^FS');

  // Barcode (Code 128, taller for 6" label)
  y = 160;
  lines.push(`^FO50,${y}\n^BY${barcodeValue.length > 32 ? '1' : '2'},3,100\n^BCN,100,Y,N,N\n^FD${escapeZpl(barcodeValue)}^FS`);

  // Separator
  y = 315;
  lines.push(`^FO15,${y}\n^GB782,3,3^FS`);

  // Product name line 1 (large)
  y += 35;
  lines.push(`^FO30,${y}\n^A0N,66,66\n^FD${productLine1}^FS`);

  // Product name line 2 (optional)
  if (productLine2) {
    y += 80;
    lines.push(`^FO30,${y}\n^A0N,66,66\n^FD${productLine2}^FS`);
  }

  // Producer (optional)
  if (producer) {
    y += 90;
    lines.push(`^FO30,${y}\n^A0N,36,36\n^FD${producer}^FS`);
  }

  // Separator
  y += 60;
  lines.push(`^FO15,${y}\n^GB782,3,3^FS`);

  // Vintage (left) + Pack size (right)
  y += 40;
  if (vintage) {
    lines.push(`^FO30,${y}\n^A0N,48,48\n^FDVintage: ${vintage}^FS`);
  }
  lines.push(`^FO${vintage ? '480' : '30'},${y + (vintage ? 10 : 0)}\n^A0N,36,36\n^FD${packSize}^FS`);

  // Separator
  y += 75;
  lines.push(`^FO15,${y}\n^GB782,3,3^FS`);

  // Owner (left, large) + Cases count (right, huge)
  y += 40;
  lines.push(`^FO30,${y + 20}\n^A0N,50,50\n^FD${ownerName}^FS`);
  lines.push(`^FO520,${y}\n^A0N,100,100\n^FD${data.quantityCases}^FS`);
  lines.push(`^FO520,${y + 105}\n^A0N,28,28\n^FDCASES^FS`);

  // Separator
  y += 150;
  lines.push(`^FO15,${y}\n^GB782,3,3^FS`);

  // Lot number
  y += 35;
  if (lotNumber) {
    lines.push(`^FO30,${y}\n^A0N,38,38\n^FD${lotNumber}^FS`);
  }

  // LWIN
  y += 50;
  lines.push(`^FO30,${y}\n^A0N,26,26\n^FDLWIN: ${lwin}^FS`);

  // Separator
  y += 45;
  lines.push(`^FO15,${y}\n^GB782,2,2^FS`);

  // QR code (left, mag 4 ~130 dots) + social footer (right)
  y += 25;
  lines.push(`^FO30,${y}\n^BQN,2,4\n^FDQA,https://www.craftculture.xyz/cold-chain.html^FS`);
  lines.push(`^FO280,${y + 40}\n${INSTAGRAM_ICON}^FS`);
  lines.push(`^FO315,${y + 43}\n^A0N,24,24\n^FD@wine.uae^FS`);
  lines.push(`^FO540,${y + 40}\n${GLOBE_ICON}^FS`);
  lines.push(`^FO575,${y + 43}\n^A0N,24,24\n^FDcraftculture.xyz^FS`);

  return `^XA\n^PW812\n^LL1218\n^PR3\n~SD20\n\n${lines.join('\n\n')}\n\n^XZ`;
};

export default generateStockPalletLabelZpl;
